problems.runner_source:
import sys


def read_ints(line: str):
    line = (line or '').strip()
    return [int(x) for x in line.split()] if line else []


def main() -> None:
    data = sys.stdin.read().splitlines()
    if not data:
        return

    n = int((data[0] or '0').strip())
    nums = read_ints(data[1])[:n] if len(data) > 1 else []
    k = int((data[2] or '0').strip()) if len(data) > 2 else 0

    freq = {}
    for x in nums:
        freq[x] = freq.get(x, 0) + 1

    from Solution import Solution  # type: ignore

    sol = Solution()
    res = sol.topKFrequent(nums, k)

    if not isinstance(res, (list, tuple)) or len(res) != k:
        sys.stdout.write('invalid')
        return

    try:
        res_ints = [int(x) for x in res]
    except Exception:
        sys.stdout.write('invalid')
        return

    if len(set(res_ints)) != len(res_ints):
        sys.stdout.write('invalid')
        return

    res_ints.sort(key=lambda v: (-freq.get(v, 0), v))
    sys.stdout.write(' '.join(str(v) for v in res_ints))


if __name__ == '__main__':
    main()

